const PlasmicDescendants = {
  root: [
    "root",
    "textbox9",
    "textbox10",
    "textbox11",
    "textarea3",
    "textbox",
    "textbox2",
    "textbox3",
    "textbox4",
    "textarea",
    "textbox5",
    "textbox6",
    "textbox7",
    "textbox8",
    "textarea2",
    "header"
  ],
  textbox9: ["textbox9"],
  textbox10: ["textbox10"],
  textbox11: ["textbox11"],
  textarea3: ["textarea3"],
  textbox: ["textbox"],
  textbox2: ["textbox2"],
  textbox3: ["textbox3"],
  textbox4: ["textbox4"],
  textarea: ["textarea"],
  textbox5: ["textbox5"],
  textbox6: ["textbox6"],
  textbox7: ["textbox7"],
  textbox8: ["textbox8"],
  textarea2: ["textarea2"],
  header: ["header"]
} as const;
type NodeNameType = keyof typeof PlasmicDescendants;
type DescendantsType<T extends NodeNameType> =
  (typeof PlasmicDescendants)[T][number];
type NodeDefaultElementType = {
  root: "div";
  textbox9: "input";
  textbox10: "input";
  textbox11: "input";
  textarea3: "textarea";
  textbox: "input";
  textbox2: "input";
  textbox3: "input";
  textbox4: "input";
  textarea: "textarea";
  textbox5: "input";
  textbox6: "input";
  textbox7: "input";
  textbox8: "input";
  textarea2: "textarea";
  header: "header";
};

type ReservedPropsType = "variants" | "args" | "overrides";
type NodeOverridesType<T extends NodeNameType> = Pick<
  PlasmicHome__OverridesType,
  DescendantsType<T>
>;
type NodeComponentProps<T extends NodeNameType> =
  // Explicitly specify variants, args, and overrides as objects
  {
    variants?: PlasmicHome__VariantsArgs;
    args?: PlasmicHome__ArgsType;
    overrides?: NodeOverridesType<T>;
  } &
    // Specify variants directly as props
    Omit<PlasmicHome__VariantsArgs, ReservedPropsType> &
    // Specify args directly as props
    Omit<PlasmicHome__ArgsType, ReservedPropsType> &
    // Specify overrides for each element directly as props
    Omit<
      NodeOverridesType<T>,
      ReservedPropsType | VariantPropType | ArgPropType
    > &
    // Specify props for the root element
    Omit<
      Partial<React.ComponentProps<NodeDefaultElementType[T]>>,
      ReservedPropsType | VariantPropType | ArgPropType | DescendantsType<T>
    >;

function makeNodeComponent<NodeName extends NodeNameType>(nodeName: NodeName) {
  type PropsType = NodeComponentProps<NodeName> & { key?: React.Key };
  const func = function <T extends PropsType>(
    props: T & StrictProps<T, PropsType>
  ) {
    const { variants, args, overrides } = React.useMemo(
      () =>
        deriveRenderOpts(props, {
          name: nodeName,
          descendantNames: PlasmicDescendants[nodeName],
          internalArgPropNames: PlasmicHome__ArgProps,
          internalVariantPropNames: PlasmicHome__VariantProps
        }),
      [props, nodeName]
    );
    return PlasmicHome__RenderFunc({
      variants,
      args,
      overrides,
      forNode: nodeName
    });
  };
  if (nodeName === "root") {
    func.displayName = "PlasmicHome";
  } else {
    func.displayName = `PlasmicHome.${nodeName}`;
  }
  return func;
}

export const PlasmicHome = Object.assign(
  // Top-level PlasmicHome renders the root element
  makeNodeComponent("root"),
  {
    // Helper components rendering sub-elements
    textbox9: makeNodeComponent("textbox9"),
    textbox10: makeNodeComponent("textbox10"),
    textbox11: makeNodeComponent("textbox11"),
    textarea3: makeNodeComponent("textarea3"),
    textbox: makeNodeComponent("textbox"),
    textbox2: makeNodeComponent("textbox2"),
    textbox3: makeNodeComponent("textbox3"),
    textbox4: makeNodeComponent("textbox4"),
    textarea: makeNodeComponent("textarea"),
    textbox5: makeNodeComponent("textbox5"),
    textbox6: makeNodeComponent("textbox6"),
    textbox7: makeNodeComponent("textbox7"),
    textbox8: makeNodeComponent("textbox8"),
    textarea2: makeNodeComponent("textarea2"),
    header: makeNodeComponent("header"),

    // Metadata about props expected for PlasmicHome
    internalVariantProps: PlasmicHome__VariantProps,
    internalArgProps: PlasmicHome__ArgProps,

    pageMetadata: generateDynamicMetadata(wrapQueriesWithLoadingProxy({}), {
      pageRoute: "/",
      pagePath: "/",
      params: {},
      query: {}
    })
  }
);

export default PlasmicHome;
